Queue<String> printerQueue = new LinkedList<>();

// Adding items (Enqueue)
printerQueue.add("Tax_Return.pdf");
printerQueue.add("Holiday_Photos.jpg");
printerQueue.add("Resume.docx");

// Seeing who is next without removing them
String nextUp = printerQueue.peek(); // Returns "Tax_Return.pdf"

// Processing items (Dequeue)
String processed = printerQueue.poll(); // Removes and returns "Tax_Return.pdf"
System.out.println("Printing: " + processed);

System.out.println("Remaining in line: " + printerQueue); 
// Output: [Holiday_Photos.jpg, Resume.docx]

